@page "/board"
@using sv_a7f56708900c446298e64f5ece81c251.Components.Board
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar OnSearchChanged="HandleSearch" />

    <div class="row g-3">
        <BoardColumn Title="To Do"
                     Status="To Do"
                     Tasks="GetFiltered("To Do")"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveRight="id => MoveTask(id, "In Progress")"
                     OnTaskCreated="model => CreateTask(model, "To Do")" />

        <BoardColumn Title="In Progress"
                     Status="In Progress"
                     Tasks="GetFiltered("In Progress")"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveLeft="id => MoveTask(id, "To Do")"
                     OnMoveRight="id => MoveTask(id, "Done")"
                     OnTaskCreated="model => CreateTask(model, "In Progress")" />

        <BoardColumn Title="Done"
                     Status="Done"
                     Tasks="GetFiltered("Done")"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveLeft="id => MoveTask(id, "In Progress")"
                     OnTaskCreated="model => CreateTask(model, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFiltered(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearch(string text) => searchText = text;

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask(TaskCardForm.NewTaskModel model, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

